// ── CHAPEL ICON ACT 2 — dynamic text ─────────────────────────
// Replaces static text; only mentions Sinhola if player has met them
function chapelIconAct2Text(G) {
  const hasSinhola = G.flags.has('met_sinhola');
  const hasButteranto = G.flags.has('met_butterantonio');
  const base = [
    "You lift it again. This time you know what you are looking at.",
  ];
  if (hasSinhola) {
    base.push("The script on the back \u2014 you have seen it now. In the container documentation that Sinhola translated. You can read fragments.");
  } else if (hasButteranto) {
    base.push("The script on the back \u2014 you have a better sense of it now. Butterantonio described the provenance document. Church Slavonic. Liturgical language.");
  } else {
    base.push("The script on the back. You have been in the container. You know the icons are from the same source.");
  }
  base.push(
    "It says: of the original pair. Entrusted. To be returned.",
    "The {ICON} in your cabin was placed here as part of the documentation of the transfer. You are the authentication. Your signature is what they need.",
    "You were sent here by whoever wants the transfer to succeed. Heritage Transfer Services sent you. The note at the bottom of your briefing said: Confirm only. Do not investigate further.",
    "You understand now what you were not supposed to investigate.",
    "You sit with this for a long time."
  );
  return base;
}


